// ─── Provider Types ──────────────────────────────────────────────
export type MigrationProvider =
  | 'runcloud' | 'forge' | 'coolify' | 'dokploy'
  | 'raw_vps' | 'ansible' | 'render' | 'heroku';

export type MigrationMode =
  | 'same_server'
  | 'cross_server_staging'
  | 'cross_server_bluegreen';

export type MigrationItemType =
  | 'docker_stack' | 'docker_container' | 'database'
  | 'cron_job' | 'domain' | 'env_file' | 'nginx_site'
  | 'systemd_service' | 'pm2_app' | 'ssl_certificate'
  | 'ansible_role' | 'coolify_project' | 'dokploy_project';

export type MigrationStatus =
  | 'pending' | 'scanning' | 'scanned' | 'configuring'
  | 'importing' | 'transferring' | 'verifying'
  | 'switching' | 'completed' | 'failed' | 'cancelled'
  | 'rolling_back' | 'rolled_back';

export type ImportStatus =
  | 'pending' | 'queued' | 'importing' | 'imported'
  | 'skipped' | 'failed' | 'rolled_back';

export type TransferStatus =
  | 'pending' | 'exporting' | 'transferring'
  | 'importing_remote' | 'deployed' | 'failed' | 'skipped';

export type VerificationStatus =
  | 'pending' | 'checking' | 'healthy' | 'unhealthy' | 'skipped';

// ─── Database Row Types ─────────────────────────────────────────
export interface ServerMigrationRow {
  id: string;
  source_server_id: string;
  target_server_id: string | null;
  provider: MigrationProvider;
  provider_version: string | null;
  provider_metadata: string | null;
  migration_mode: MigrationMode;
  status: MigrationStatus;
  current_phase: string | null;
  scan_started_at: number | null;
  scan_completed_at: number | null;
  import_started_at: number | null;
  import_completed_at: number | null;
  verification_started_at: number | null;
  verification_completed_at: number | null;
  cutover_started_at: number | null;
  cutover_completed_at: number | null;
  total_discovered: number;
  total_selected: number;
  total_imported: number;
  total_failed: number;
  total_verified: number;
  source_cleanup_mode: 'keep' | 'stop' | 'remove';
  scan_log: string | null;
  last_error: string | null;
  rollback_log: string | null;
  created_at: number;
  updated_at: number;
}

export interface DiscoveredItemRow {
  id: string;
  migration_id: string;
  source_server_id: string;
  item_type: MigrationItemType;
  remote_key: string;
  display_name: string;
  description: string | null;
  payload_json: string;
  provider_source: string | null;
  selected: number;
  priority: number;
  depends_on: string | null;
  import_status: ImportStatus;
  local_record_type: string | null;
  local_record_id: string | null;
  transfer_status: TransferStatus;
  transfer_log: string | null;
  transfer_bytes: number | null;
  verification_status: VerificationStatus;
  verification_message: string | null;
  rollback_data: string | null;
  error_message: string | null;
  retry_count: number;
  created_at: number;
  updated_at: number;
}

// ─── Provider Detection ─────────────────────────────────────────
export interface ProviderDetectionResult {
  provider: MigrationProvider;
  version: string | null;
  confidence: number; // 0-1
  metadata: Record<string, unknown>;
}

// ─── Discovery ──────────────────────────────────────────────────
export interface DiscoveredItem {
  id: string;
  itemType: MigrationItemType;
  remoteKey: string;
  displayName: string;
  description?: string;
  payload: Record<string, unknown>;
  providerSource: MigrationProvider;
  priority: number;
  dependsOn: string[];
  estimatedSize?: number;
}

export interface ScanPhase {
  id: string;
  label: string;
  status: 'pending' | 'running' | 'completed' | 'failed' | 'skipped';
  itemsFound: number;
}

export interface ScanProgress {
  migrationId: string;
  serverId: string;
  provider: MigrationProvider;
  phase: string;
  phases: ScanPhase[];
  message: string;
  totalItemsFound: number;
}

export interface ScanResult {
  migrationId: string;
  provider: MigrationProvider;
  providerVersion: string | null;
  items: DiscoveredItem[];
  warnings: string[];
  errors: string[];
}

// ─── Import ─────────────────────────────────────────────────────
export interface ImportItemResult {
  itemId: string;
  success: boolean;
  localRecordType?: string;
  localRecordId?: string;
  rollbackData?: RollbackAction;
  error?: string;
}

export interface ImportProgress {
  migrationId: string;
  phase: 'starting' | 'importing' | 'verifying' | 'completed' | 'failed';
  currentItem?: string;
  currentIndex?: number;
  totalItems?: number;
  message: string;
  error?: string;
}

// ─── Transfer (Cross-Server) ────────────────────────────────────
export interface TransferProgress {
  migrationId: string;
  itemId: string;
  phase: 'exporting' | 'transferring' | 'importing_remote' | 'deploying' | 'completed' | 'failed';
  progress: number; // 0-100
  bytesTransferred?: number;
  totalBytes?: number;
  message: string;
  error?: string;
}

// ─── Verification ───────────────────────────────────────────────
export type VerificationCheckType =
  | 'http_health' | 'port_listen' | 'process_running' | 'docker_healthy'
  | 'db_connection' | 'cron_active' | 'dns_resolution' | 'ssl_valid';

export interface VerificationCheck {
  itemId: string;
  itemName: string;
  checkType: VerificationCheckType;
  status: VerificationStatus;
  message: string;
  details?: string;
}

export interface VerificationProgress {
  migrationId: string;
  currentIndex: number;
  totalItems: number;
  currentItemName: string;
  phase: 'starting' | 'checking' | 'completed';
  checks: VerificationCheck[];
}

// ─── Rollback ───────────────────────────────────────────────────
export type RollbackAction =
  | { type: 'delete_stack'; stackId: string; projectName: string }
  | { type: 'delete_database_record'; databaseId: string }
  | { type: 'remove_cron'; serverId: string; cronLine: string; user: string }
  | { type: 'delete_domain'; domainId: string }
  | { type: 'remove_directory'; serverId: string; path: string }
  | { type: 'restore_compose'; stackId: string; previousContent: string }
  | { type: 'noop'; reason: string };

// ─── Decommission ───────────────────────────────────────────────
export interface DecommissionStep {
  id: string;
  label: string;
  command: string;
  dangerous: boolean;
  executed: boolean;
  result?: { success: boolean; output: string };
}

export interface DecommissionPlan {
  provider: MigrationProvider;
  steps: DecommissionStep[];
  warnings: string[];
}

// ─── Blue-Green Cutover ─────────────────────────────────────────
export interface CutoverPlan {
  migrationId: string;
  domains: Array<{
    domain: string;
    currentIP: string;
    targetIP: string;
  }>;
  healthChecks: VerificationCheck[];
  estimatedDowntime: string;
}

// ─── Engine Input Types ─────────────────────────────────────────
export interface StartMigrationInput {
  sourceServerId: string;
  targetServerId?: string;
  mode: MigrationMode;
}

export interface ExecuteMigrationInput {
  migrationId: string;
  selection: Record<string, boolean>;
}
